module mux4to1 (
    input [1:0] sel,
    input [3:0] in0,
    input [3:0] in1,
    input [3:0] in2,
    input [3:0] in3,
    output [3:0] out
);

    reg [3:0] invalid_mux;  // Multiplexer output register

    always @(*) begin
        case (sel)
            2'b00: invalid_mux = in0;
            2'b01: invalid_mux = in1;
            2'b10: invalid_mux = in2;
            2'b11: invalid_mux = in3;
            default: invalid_mux = 4'b0000;  // Default case (should not occur)
        endcase
    end

    assign out = invalid_mux;

endmodule
